<template>
  <b-field label="Asset" :addons="false" class="info">
    <b-tooltip label="Please list all assets in your possession." position="is-left" size="is-medium" type="is-dark" animated multilined v-once>
      <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
    </b-tooltip>
    <b-field ref="data">
      <b-input v-model="asset.type" type="text" icon="credit-card" style="flex:3;" placeholder="I own"></b-input>
      <b-input v-model="asset.value"  icon="dollar-sign" style="flex:2;" placeholder="Worth CAD"></b-input>
      <span class="control">
        <button class="button is-outlined is-primary" v-if="adding" :disabled="fields === 6" @click="addField">
          <i class="fas fa-plus"></i>&ensp;Add</button>
        <button class="button is-outlined is-danger" v-else @click="removeField">
          <i class="fas fa-minus"></i>&ensp;Remove</button>
      </span>
    </b-field>
  </b-field>
</template>

<script>
export default {
  data() {
    return {
      adding: true,
      asset: {
        type: null,
        value: null
      }
    };
  },
  methods: {
    addField() {
      this.$emit("addfield");
      this.adding = !this.adding;
    },
    removeField() {
      this.$emit("removefield");
      this.adding = !this.adding;
    }
  },
  props: {
    fields: Number
  }
};
</script>