<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="95" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Please List Other Properties You Own</p>
      <p slot="message">
        We are almost at the end. We just need to collect your existing properties information to finalize your mortgage assesment. If you own properties, please list them all in the address blocks provided.
      </p>
    </message-modal>
    <div class="container">
      <div class="box">

        <address-block message="Your owned property address" icon="building" :page="additionalProperties"></address-block>

        <div class="columns is-centered">
          <div class="column is-half is-one-third-desktop">
            <b-field label="Property value" :addons="false" class="info">
              <b-tooltip label="What is this property currently worth?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input v-model="additionalProperties.value"  icon="dollar-sign" placeholder="CAD" expanded></b-input>
            </b-field>
          </div>
          <div class="column is-half is-one-third-desktop">
            <b-field label="Property type" :addons="false" class="info">
              <b-tooltip label="How do you classify this property?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-select v-model="additionalProperties.type" type="text" icon="building" placeholder="It's a" expanded>
                <option value="Condo">Condo</option>
                <option value="Triplex">Triplex</option>
                <option value="House">House</option>
              </b-select>
            </b-field>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column">
            <b-field label="Property taxes" :addons="false" class="info">
              <b-tooltip label="What is your annual property tax on this property?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input v-model="additionalProperties.propertyTaxes" icon="hand-holding-usd" placeholder="CAD annually"  expanded></b-input>
            </b-field>
          </div>
          <div class="column is-one-third-desktop">
            <b-field label="Occupancy status" :addons="false" class="info">
              <b-tooltip label="Do you live on or rent out this property?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-select v-model="additionalProperties.occupancy" type="text" icon="key" placeholder="The property is" expanded>
                <option value="rental">Rented out</option>
                <option value="owned">Owner occupied</option>
              </b-select>
            </b-field>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-half is-one-third-desktop">
            <b-field label="Is this mortgaged" :addons="false" class="info">
              <b-tooltip label="Is there a mortgage on this property?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <div class="input is-borderless is-shadowless">
                <b-radio v-model="additionalProperties.mortgaged" native-value="Yes">
                  Yes
                </b-radio>
                <b-radio v-model="additionalProperties.mortgaged" native-value="No">
                  No
                </b-radio>
              </div>
            </b-field>
          </div>
          <div class="column is-one-third-desktop">
            <transition name="fadeUp" mode="out-in">
              <b-field label="Rental income" :addons="false" class="info" v-if="additionalProperties.occupancy === 'rental'">
                <b-tooltip label="How much rent do you collect per month?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-input v-model="additionalProperties.rentalIncome" icon="dollar-sign" placeholder="CAD per month"  expanded></b-input>
              </b-field>
            </transition>
          </div>
        </div>

        <transition name="fadeUp" mode="out-in">
          <!-- <div class="columns is-centered" v-if="additionalProperties.mortgage === 'Yes'"> -->
          <div class="columns is-centered">
            <div class="column is-one-third-desktop">
              <b-field label="Mortgage amount" :addons="false" class="info">
                <b-tooltip label="What are your mortgage payments?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-field>
                  <b-input v-model="additionalProperties.mortgagePayment"  icon="hand-holding-usd" placeholder="CAD" expanded></b-input>
                  <div class="control">
                    <b-select placeholder="CAD" icon="dollar-sign" v-model="additionalProperties.mortgagePaymentType">
                      <option value="monthly">Monthly</option>
                      <option value="bi-weekly">Bi-weekly</option>
                    </b-select>
                  </div>
                </b-field>
              </b-field>
            </div>
            <div class="column is-one-third-desktop">
              <b-field label="Mortgage rate" :addons="false" class="info">
                <b-tooltip label="What is your mortgage rate?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-field>
                  <b-input v-model="additionalProperties.mortgageRate"  icon="percent" placeholder="CAD" expanded></b-input>
                  <div class="control">
                    <b-select placeholder="Type" icon="signature" v-model="additionalProperties.mortgageRateType">
                      <option value="fixed">Fixed</option>
                      <option value="variable">Variable</option>
                    </b-select>
                  </div>
                </b-field>
              </b-field>
            </div>
            <div class="column">
              <b-field label="Mortgage lender" :addons="false" class="info">
                <b-tooltip label="Which bank is your mortgage with?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-input v-model="additionalProperties.mortgageLender" icon="university" placeholder="My mortgage is with" type="text" expanded></b-input>
              </b-field>
            </div>
          </div>
        </transition>

        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <hr>
          </div>
        </div>

        <to-page back="/assets" next="/signatures" text="Sign the Form"></to-page>

      </div>
    </div>
  </div>
</template>

<script>
import addressBlock from "../components/address-block.vue";
export default {
  data() {
    return {
      page: "Page 7",
      heading: "Your Properties Form",
      toggled: false,
      additionalProperties: {
        value: null,
        type: null,
        occupancy: null,
        rentalIncome: null,
        propertyTaxes: null,
        mortgaged: null,
        mortgagePayment: null,
        mortgagePaymentType: null,
        mortgageRate: null,
        mortgageRateType: null,
        address: {
          main: null,
          city: null,
          province: "Ontario",
          postal: null
        }
      }
    };
  },
  components: {
    addressBlock
  }
};
</script>
