<template>
  <div class="columns is-centered">
    <div class="column is-half is-one-third-widescreen">
      <p class="has-text-weight-bold has-text-grey-light is-size-5">
        <i class="fas fa-car-side"></i>
        Your list of assets (up-to 5)
      </p>
      <transition-group name="fadeUp" mode="out-in">
        <asset :fields="assetFields" v-for="row in assetFields" :key="row" @addfield="addAssetField" @removefield="removeAssetField"></asset>
      </transition-group>
    </div>
    <div id="test" class="column is-half is-one-third-widescreen">
      <p class="has-text-weight-bold has-text-grey-light is-size-5">
        <i class="fas fa-credit-card"></i>
        Your list of liabilities (up-to 5)
      </p>
      <transition-group name="fadeUp" mode="out-in">
        <liability :fields="liabilityFields" v-for="row in liabilityFields" :key="row" @addfield="addLiabilityField" @removefield="removeLiabilityField"></liability>
      </transition-group>
    </div>
  </div>
</template>

<script>
import liability from "./liability.vue";
import asset from "./asset.vue";
export default {
  data() {
    return {
      assetFields: 1,
      liabilityFields: 1
    };
  },
  methods: {
    addAssetField(e) {
      if (this.assetFields < 6) {
        this.assetFields += 1;
      }
    },
    removeAssetField(e) {
      if (this.assetFields > 1) {
        this.assetFields -= 1;
      }
    },
    addLiabilityField(e) {
      if (this.liabilityFields < 6) {
        this.liabilityFields += 1;
      }
    },
    removeLiabilityField(e) {
      if (this.liabilityFields > 1) {
        this.liabilityFields -= 1;
      }
    }
  },
  components: {
    liability,
    asset
  }
};
</script>
