<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="75" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Let's Talk Employment</p>
      <p slot="message">
        To offer you the best possible rate and chance of qualifying for a mortgage, we need collect your employment information to prepare the best client profile to the banks.
      </p>
    </message-modal>

    <div class="container">
      <div class="box">
        <div class="columns is-centered">
          <div class="column is-one-third">
            <b-field label="Are you self-employed?" :addons="false" class="info">
              <b-tooltip label="Check yes if you reside with the main applicant." position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <div class="input is-borderless is-shadowless">
              <b-radio v-model="employmentPage.selfEmployed" native-value="Yes" @input="employmentRoute">
                Yes
              </b-radio>
              <b-radio v-model="employmentPage.selfEmployed" native-value="No" @input="employmentRoute">
                No
              </b-radio>
              </div>
            </b-field>
          </div>
          <div class="column is-one-third">
            <transition name="fadeUp" mode="out-in">
            <b-field label="Business type" :addons="false" class="info" v-if="$route.path === '/employment/self'">
              <b-tooltip label="What category of business do you operate?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-select expanded icon="building" placeholder="Most relevant">
                <option value="Sole Proprietor">Sole Proprietor</option>
                <option value="Corporation">Corporation</option>
                <option value="Partnership">Partnership</option>
              </b-select>
            </b-field>
            </transition>
          </div>
        </div>

        <router-view :employmentPage="employmentPage"></router-view>

        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <hr>
          </div>
        </div>

        <to-page back="/personal" next="/assets" text="Go to Assets & Liabilities"></to-page>

      </div>
    </div>
  </div>
</template>

<script>
import router from "../router";

export default {
  data() {
    return {
      page: "Page 5",
      heading: "Your Employment Details",
      toggled: false,
      employmentPage: {
        employerName: null,
        title: null,
        selfEmployed: null,
        income: null,
        timeAtIndustry: null,
        timeAtJob: null,
        address: {
          main: null,
          city: null,
          province: "Ontario",
          postal: null
        }
      }
    };
  },
  //clear the other form just in case they submit both pages
  methods: {
    employmentRoute(e) {
      if (e === "Yes") {
        router.replace({ path: "/employment/self" });
      } else if (e === "No") {
        router.replace({ path: "/employment/company" });
      } else {
        return false;
      }
    }
  }
};
</script>