<template>
  <div class="container box" ref="heading">
    <div class="columns is-centered">
      <div class="column is-two-thirds">
        <h1 class="title has-text-grey-dark">{{page}}&ensp;&mdash;&ensp;{{heading}}&nbsp;
          <i class="fas fa-info-circle is-size-4" @click="$emit('toggled')"></i>
        </h1>
        <progress class="progress is-small is-primary" :value="progress" max="100">75% complete</progress>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  mounted() {
    this.$refs.heading.classList.add('fadeUp-enter-active')
    setTimeout(() => {
      this.$refs.heading.classList.remove('fadeUp-enter-active')
    }, 460);
  },
  props: {
    page: String,
    heading: String,
    progress: String
  }
};
</script>

<style lang="scss">
.fas.fa-info-circle {
  vertical-align: top;
  color: #167df0;
  cursor: pointer;
}
.wtf {
  background: #e43 !important;
}
</style>