<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="100" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Please Read the Terms Carefully</p>
      <p slot="message">
        To finalize your mortgage application, we need your signatures. Please go over the terms below, and feel free to backtrack and make necessary adjustments to your forms.
      </p>
    </message-modal>
    <div class="container">
      <div class="box">
        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <section class="content">
              <h1>Disclaimer:</h1>
              <p>
                I, the undersigned, herby declare that all the information provided herein is to the best of my knowledge and belief to be true, complete and correct and I understand that it may be used to determine my credit worthiness. In order to assess my ability to meet my financial obligations I consent and authorize the submitting organization and its agents or assigns:
              </p>
              <ul>
                <li>To request and obtain personal information about me on an ongoing basis from credit bureaus from information you previously collected about me in order to assess my credit history.</li>
                <li>To release and exchange my personal information on an ongoing basis with credit bureaus in order to protect me, ensure the completeness of my information and maintain the integrity of the credit bureau agency:</li>
                <li>To co-operate with local, provincial and national authorities in the investigation of unlawful or improper activities in order to protect myself and Dominioin Lending Centres from fraudulent transactions: and</li>
                <li>To disclose my personal information where necessary to protect my interests, and that of Dominion Lending Centres.</li>
              </ul>
            </section>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <hr>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-5 has-text-centered">
            <b-field :label="mainSig" style="white-space: pre;">
              <canvas id="applicant"></canvas>
            </b-field>
            <p class="has-text-weight-bold">Signature</p>
          </div>
          <div class="column is-5 has-text-centered">
            <b-field :label="coSig" style="white-space: pre;">
              <canvas id="co-applicant"></canvas>
            </b-field>
            <p class="has-text-weight-bold">Signature</p>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <hr>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-1 has-text-centered">
            <b-field label="I agree">
              <b-checkbox value="I agree"></b-checkbox>
            </b-field>
          </div>
          <div class="column is-7">
            <section class="content">
              <p>
                Canada’s new Anti-Spam Legislation is effective as of July 1, 2014. Under this new legislation, I am required to obtain your consent in order to send you communications about the latest mortgage news, events, products and services.
              </p>
            </section>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-two-thirds has-text-centered">
            <hr>
            <button class="button is-primary is-large is-rounded">Submit My Application</button>
          </div>
        </div>

      </div>
    </div>
  </div>
</template>

<script>
import SignaturePad from "signature_pad";
export default {
  mounted() {
    var signatures = document.querySelectorAll("canvas");
    signatures.forEach(sig => {
      new SignaturePad(sig, {
        penColor: "rgb(32, 42, 144)"
      });
    });
    // resizeSigs();
  },
  // updated() {
  //   resizeSigs();
  // },
  data() {
    return {
      page: "Page 8",
      heading: "Your Signatures",
      toggled: false,
      applicantName: "James Bowden",
      coapplicantName: "Ludmila Barkhatova"
    };
  },
  methods: {
    resizeSigs() {
      var ratio = Math.max(window.devicePixelRatio || 1, 1);
      canvas.width = canvas.offsetWidth * ratio;
      canvas.height = canvas.offsetHeight * ratio;
      canvas.getContext("2d").scale(ratio, ratio);
      signaturePad.clear();
    },
    formatDate(date) {
      var monthNames = [
        "January",
        "February",
        "March",
        "April",
        "May",
        "June",
        "July",
        "August",
        "September",
        "October",
        "November",
        "December"
      ];

      var day = date.getDate();
      var monthIndex = date.getMonth();
      var year = date.getFullYear();

      return day + ", " + monthNames[monthIndex] + ", " + year;
    }
  },
  computed: {
    mainSig() {
      return `${this.applicantName} \n Signed on ${this.formatDate(
        new Date()
      )}`;
    },
    coSig() {
      return `${this.coapplicantName} \n Signed on ${this.formatDate(
        new Date()
      )}`;
    }
  }
};
</script>

<style>
canvas {
  border: 1px solid gainsboro;
  border-bottom-color: black;
  border-bottom-width: 3px;
  border-radius: 6px;
}
</style>
