import Vue from 'vue'
import Router from 'vue-router'
import Home from './views/Home.vue'
import start from './views/start.vue'
import propertyOccupant from './views/property-occupant.vue'
import propertyRental from './views/property-rental.vue'
import personalForm from './views/personal-form.vue'
import employmentForm from './views/employment-form.vue'
